"use client"

import { useFinancial } from "@/hooks/useFinancial"
import { Navigation } from "@/components/navigation"
import { Card } from "@/components/ui/card"
import { CATEGORIES } from "@/lib/constants"
import { AlertCircle } from "lucide-react"
import { formatCurrency } from "@/lib/utils"

/**
 * Interface para tipagem dos dados de orçamento.
 * Define a estrutura esperada para cada categoria monitorada.
 */
interface Budget {
  id: string;
  category: string;
  spent: number;
  limit: number;
}

export default function BudgetsPage() {
  const { data } = useFinancial()

  return (
    <div className="flex h-screen bg-background text-foreground overflow-hidden">
      <Navigation />
      
      <main className="flex-1 overflow-y-auto">
        <div className="p-8 max-w-[1400px] mx-auto">
          
          {/* Cabeçalho da Página */}
          <div className="mb-8">
            <h2 className="text-3xl font-bold uppercase tracking-tight">Orçamentos</h2>
            <p className="text-muted-foreground mt-1">
              Defina e acompanhe seus limites de gastos por categoria.
            </p>
          </div>

          <div className="grid grid-cols-1 gap-4">
            {data?.budgets?.map((budget: Budget) => {
              const category = CATEGORIES.find((c) => c.id === budget.category)
              
              // Cálculos de métricas de consumo
              const percentage = (budget.spent / budget.limit) * 100
              const isOverBudget = budget.spent > budget.limit

              return (
                <Card key={budget.id} className="p-6 border-border/50 hover:bg-muted/10 transition-colors">
                  <div className="flex items-start justify-between mb-4">
                    <div className="flex items-center gap-4">
                      {/* Ícone e Nome da Categoria */}
                      <div className="w-12 h-12 rounded-full bg-primary/10 flex items-center justify-center text-2xl">
                        {category?.icon}
                      </div>
                      <div>
                        <h3 className="text-lg font-semibold">{category?.name}</h3>
                        <p className="text-sm text-muted-foreground">
                          Gasto: <span className="font-bold text-foreground">{formatCurrency(budget.spent)}</span> de{" "}
                          <span className="font-medium">{formatCurrency(budget.limit)}</span>
                        </p>
                      </div>
                    </div>

                    {/* Alerta de Limite Excedido */}
                    {isOverBudget && (
                      <div className="flex items-center gap-2 text-red-500 bg-red-500/10 px-3 py-1.5 rounded-full border border-red-500/20">
                        <AlertCircle className="w-4 h-4" />
                        <span className="text-xs font-bold uppercase">Limite Excedido</span>
                      </div>
                    )}
                  </div>

                  {/* Barra de Progresso Visual */}
                  <div className="relative w-full bg-muted rounded-full h-3 overflow-hidden">
                    <div
                      className={`h-full rounded-full transition-all duration-700 ${
                        percentage > 100 
                          ? "bg-red-500" 
                          : percentage > 80 ? "bg-yellow-500" : "bg-emerald-500"
                      }`}
                      style={{ width: `${Math.min(percentage, 100)}%` }}
                    />
                  </div>

                  <div className="flex justify-between items-center mt-3">
                    <p className="text-xs font-medium text-muted-foreground uppercase tracking-wider">
                      {percentage.toFixed(0)}% do orçamento utilizado
                    </p>
                    {percentage > 100 && (
                      <p className="text-xs font-bold text-red-500 tracking-tight">
                        Atenção: Reduza os gastos nesta categoria.
                      </p>
                    )}
                  </div>
                </Card>
              )
            })}

            {/* Estado vazio caso não haja orçamentos definidos */}
            {(!data?.budgets || data.budgets.length === 0) && (
              <div className="text-center py-20 border-2 border-dashed rounded-xl border-border/50">
                <p className="text-muted-foreground">Nenhum orçamento configurado no momento.</p>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  )
}